 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { Button, Modal, ModalVariant } from '@patternfly/react-core';
 4	
 5	type Props = {
 6	  handleRedirect: (event: React.MouseEvent<HTMLButtonElement>) => void;
 7	};
 8	
 9	const ConfirmationModal: React.FC<Props> = ({ handleRedirect }) => {
10	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
11	
12	  return (
13	    <Modal
14	      actions={[
15	        <Button id="leave" key="leave" onClick={handleRedirect} variant="primary">
16	          {t('Leave')}
17	        </Button>,
18	        <Button id="stay" key="stay" onClick={handleRedirect} variant="link">
19	          {t('Stay')}
20	        </Button>,
21	      ]}
22	      aria-describedby="modal-title-icon-description"
23	      className="redirect-modal"
24	      isOpen={true}
25	      showClose={false}
26	      title={t('Do you want to leave this page?')}
27	      titleIconVariant="warning"
28	      variant={ModalVariant.small}
29	    >
30	      {t('Changes you made may not be saved.')}
31	    </Modal>
32	  );
33	};
34	
35	export default ConfirmationModal;

